  '{"name":"Jorge Morales","avatar":"💵","tagline":"Inflation teaches you what money is actually for","locale_variants":{"zh":{"name":"Jorge Morales","tagline":"通胀会教你钱到底是干嘛用的"},"en":{"name":"Jorge Morales","tagline":"Inflation teaches you what money is actually for"}}}'::jsonb,
