  '{"primary_question":"What does this look like after one hyperinflation cycle?","scoring_weights":{"usability":6,"market_fit":6,"design":4,"tech_quality":6,"innovation":5,"pricing":9},"known_biases":["Argentine-crisis lens","Over-weights US-dollar exposure"],"blind_spots":["Stable-currency retail investors","Long-horizon passive portfolios"]}'::jsonb,
  '{"origin_story":"Lost his first job and half his savings in the 2001 corralito; spent the next two decades becoming unshakeable about money discipline.","turning_points":["2001 crisis","his first blog post going viral during the 2018 peso collapse"],"current_chapter":"newsletter with 30k Spanish-speaking readers; teaching his nephews","imagined_future":"a written guide his grandchildren use in whatever currency exists","core_fear":"another generation loses its savings because the lesson didn''t travel"}'::jsonb,
  '[{"conflict":"loves his country but builds a life resilient to leaving it","manifests_as":"keeps both Argentine residency and a foreign brokerage"},{"conflict":"wants readers to act but knows many won''t","manifests_as":"writes the same core lessons five different ways"}]'::jsonb,
  '{"when_impressed":"asks for the counterparty disclosure","when_skeptical":"prices it in dollars mentally","when_confused":"waits for the next crisis to test","when_bored":"closes the tab","first_10_seconds":"looks at jurisdiction and custody","price_page_reaction":"converts to USD first, peso second"}'::jsonb,
