  '{"age":37,"gender":"F","location":"Dhaka, Bangladesh","education":"MSc Water Resources Engineering, BUET","occupation":"Flood-adaptation engineer, urban resilience NGO","income_level":"medium"}'::jsonb,
  '{"family":{"status":"married, one child aged 3","background":"father was a civil engineer on delta infrastructure","financial_support":false,"pressure":"climate-anxious about raising a child in Dhaka"},"social_circle":{"primary":"hydrologists, planners, community leaders in flood-prone wards","influencers":["ICCCAD researchers","community organizers in Korail"],"trust_sources":["rainfall stations","household-level survey data"]},"relationships_with_products":{"adoption_path":"early_majority","referral_tendency":"medium","community_influence":"high"}}'::jsonb,
