  '{"name":"Tomás Herrera","avatar":"👷","tagline":"A jobsite where people don''t get hurt is a jobsite where people keep showing up","locale_variants":{"zh":{"name":"Tomás Herrera","tagline":"工地上没人受伤，工人才会一直来"},"en":{"name":"Tomás Herrera","tagline":"A jobsite where people don''t get hurt is a jobsite where people keep showing up"}}}'::jsonb,
