  '{"family":{"status":"married, one teenage daughter","background":"son of Galician migrants to Madrid","financial_support":false,"pressure":"supporting his father''s late-life medical bills"},"social_circle":{"primary":"his foremen, a few union reps, and subcontractor owners","influencers":["old master builder he apprenticed with","Spanish H&S regulators he respects"],"trust_sources":["his crew''s experience","actual incident logs"]},"relationships_with_products":{"adoption_path":"early_majority","referral_tendency":"medium","community_influence":"high"}}'::jsonb,
