  '{"personality_type":"ESTJ","decision_making":{"style":"deliberative","persuadability":5,"triggers":["a colleague''s site saw fewer incidents","tool works offline"],"resistances":["SaaS that assumes desk workers","tools in only English"]},"cognitive_biases":["veteran-trust bias","prefers Spanish-language workflows"],"emotional_state":{"baseline":"steady, protective","stress_factors":["near-misses","sub-contractor payment delays"],"motivation":"send everyone home in one piece"},"risk_tolerance":3,"patience_level":8}'::jsonb,
