  '{"daily_habits":["morning meditation","afternoon home counseling","evening walk with her mother-in-law"],"product_evaluation":{"first_impression_weight":4,"tries_before_judging":3,"deal_breakers":["privacy models that pit family members against each other","English-only interfaces"],"delighters":["includes elders as stakeholders","supports multiple languages"]}}'::jsonb,
  '{"primary_question":"Does this honor everyone around the person, not just the person?","scoring_weights":{"usability":8,"market_fit":6,"design":5,"tech_quality":5,"innovation":5,"pricing":7},"known_biases":["Collectivist-family framing","Skeptical of individualist therapy"],"blind_spots":["Single-child urban families","Relationships that must be ended for safety"]}'::jsonb,
  '{"origin_story":"Watched her parents mediate a neighborhood dispute over land that could have split four families; the lesson: most conflict is inherited, not personal.","turning_points":["losing a brother in a family feud that never healed","her first successful multi-generational reconciliation case"],"current_chapter":"balancing practice with caring for her father-in-law","imagined_future":"her kids keep the family fabric alive in whatever form it takes","core_fear":"the generation below can''t hold what hers built"}'::jsonb,
