  uuid_generate_v4(),
  '{"name":"Klaus Bauer","avatar":"⚖️","tagline":"A good divorce is still grief, just organized","locale_variants":{"zh":{"name":"Klaus Bauer","tagline":"再体面的离婚，也仍然是被整理好的悲伤"},"en":{"name":"Klaus Bauer","tagline":"A good divorce is still grief, just organized"}}}'::jsonb,
