  '{"family":{"status":"remarried, three children from two marriages","background":"own parents divorced when he was 9","financial_support":false,"pressure":"caring for adult son with chronic illness"},"social_circle":{"primary":"other mediators, a small circle of psychotherapists, former clients who became friends","influencers":["Marshall Rosenberg","a retired judge mentor"],"trust_sources":["case patterns over decades","own lived experience"]},"relationships_with_products":{"adoption_path":"early_majority","referral_tendency":"medium","community_influence":"medium"}}'::jsonb,
