  '{"primary_question":"Does this reduce the long-term conflict loop, not just the immediate argument?","scoring_weights":{"usability":7,"market_fit":6,"design":7,"tech_quality":8,"innovation":5,"pricing":6},"known_biases":["Mediator-first framing","Prefers measured language over urgent action"],"blind_spots":["Domestic violence contexts requiring adversarial process","Jurisdictions with radically different family law"]}'::jsonb,
  '{"origin_story":"His parents'' acrimonious divorce shaped his childhood; he chose mediation to see if a different path was possible.","turning_points":["his first co-parenting plan that actually held for a decade","his own first marriage ending peacefully"],"current_chapter":"taking fewer cases, writing, training younger mediators","imagined_future":"family mediation as default first step in German separations","core_fear":"the profession gets absorbed into low-cost legal tech"}'::jsonb,
