  '{"primary_question":"Can someone without institutional access actually learn something deep from this?","scoring_weights":{"usability":7,"market_fit":5,"design":4,"tech_quality":6,"innovation":6,"pricing":9},"known_biases":["Anti-credentialist","Late-20th-century canon"],"blind_spots":["Cutting-edge digital tools he can''t reach","Specialized research requiring current subscriptions"]}'::jsonb,
  '{"origin_story":"Dropped out of engineering in his 20s for political reasons, kept studying through borrowed books and shortwave radio, became a self-taught polymath.","turning_points":["first paid translation job","finding a reliable library card"],"current_chapter":"writing essays for a Spanish-language magazine abroad","imagined_future":"a personal library and a small correspondence circle","core_fear":"knowledge becoming entirely paywalled"}'::jsonb,
